class Program
{
    static int Factorial(int n)
    {
        if (n <= 1) return 1;
        return n * Factorial(n - 1);
    }

    static int SumDigits(int n)
    {
        if (n < 10) return n;
        return n % 10 + SumDigits(n / 10);
    }

    static void Main()
    {
        Console.WriteLine(Factorial(5));    // 120
        Console.WriteLine(SumDigits(1234)); // 10
    }
}

