class Program
{
    static long FibIterative(int n)
    {
        if (n <= 1) return n;
        long a = 0, b = 1;
        for (int i = 2; i <= n; i++)
        {
            long next = a + b;
            a = b;
            b = next;
        }
        return b;
    }

    static void Main()
    {
        Console.WriteLine(FibIterative(10));  // 55
        Console.WriteLine(FibIterative(50));  // 12586269025
    }
}

